from fastapi import FastAPI, Path

app = FastAPI()

@app.get("/products/{product_id}")
async def get_product(
    product_id: int = Path(..., title="Product ID", ge=1, le=9999)
):
    return {"product_id": product_id, "message": f"Product {product_id} details"}

@app.get("/products/{product_id}/reviews/{review_id}")
async def get_review(
    product_id: int,
    review_id: int = Path(..., ge=1)
):
    return {"product_id": product_id, "review_id": review_id}
